Key requirement: byte-identical static prefix for stages 2 and 3.

```typescript
import type { GitLabEpic, GitLabIssue } from '../../services/gitlab/types';

interface StaticPrefix {
  systemRules: string;
  epicXML: string;
  issueXML: string;
}

/**
 * Returns byte-identical static prefix used by all 3 stages.
 * Format:
 * <system>...</system>
 * <epic>...</epic>
 * <issue>...</issue>
 */
export function buildStaticPrefix(epic: GitLabEpic, issue: GitLabIssue): StaticPrefix {
  const systemRules = `You are refining a GitLab issue grounded in its parent epic.

Rules:
1. Preserve GitLab quick actions (/label, @user, #ref)
2. Do NOT emit H1-H6 markdown headers (##, ###, etc) in refined body
3. Structure refined body with sections: Summary, Context, Acceptance Criteria, Technical Notes
4. Base all analysis on the epic's intent and the issue's original content`;

  const epicXML = `<epic>
<title>${epic.title}</title>
<description>${epic.description || ''}</description>
</epic>`;

  const issueXML = `<issue>
<iid>${issue.iid}</iid>
<title>${issue.title}</title>
<description>${issue.description || ''}</description>
</issue>`;

  return { systemRules, epicXML, issueXML };
}

export function assembleMessages(prefix: StaticPrefix, stagePrompt: string) {
  return [
    { role: 'system' as const, content: prefix.systemRules },
    { role: 'user' as const, content: `${prefix.epicXML}\n${prefix.issueXML}\n\n${stagePrompt}` }
  ];
}
```

