import { aiClient } from '../../../services/ai/aiClient';
import { comprehensionSchema, toStrictJsonSchema } from '../schemas';
import { buildStaticPrefix, assembleMessages } from '../promptAssembly';
import { comprehensionPrompt } from './prompt';

export async function runComprehension(
  epic: GitLabEpic,
  issue: GitLabIssue
): Promise<{ result: ComprehensionOutput; cachedTokens: number }> {
  const prefix = buildStaticPrefix(epic, issue);
  const messages = assembleMessages(prefix, comprehensionPrompt);

  const response = await aiClient.chat({
    messages,
    temperature: 0.2,
    reasoning_effort: 'minimal',
    response_format: {
      type: 'json_schema',
      json_schema: {
        name: 'comprehension',
        schema: toStrictJsonSchema(comprehensionSchema),
        strict: true
      }
    }
  });

  const parsed = comprehensionSchema.parse(JSON.parse(response.content));
  const cachedTokens = response.usage?.prompt_tokens_details?.cached_tokens || 0;

  return { result: parsed, cachedTokens };
}
```

