import { runComprehension } from './comprehension/runComprehension';
import { runRefinement } from './refinement/runRefinement';
import { runValidation } from './validation/runValidation';
import type { GitLabEpic, GitLabIssue } from '../../services/gitlab/types';

export interface IssuePipelineResult {
  comprehension: ComprehensionOutput;
  refinedBody: string;
  validation: ValidationOutput;
  cachedTokens: { comprehension: number; refinement: number; validation: number };
}

/**
 * Pure orchestrator: runs 3 stages sequentially.
 * No store access. Caller handles state management.
 */
export async function runIssuePipeline(
  epic: GitLabEpic,
  issue: GitLabIssue
): Promise<IssuePipelineResult> {
  // Stage 1: Comprehension
  const { result: comprehension, cachedTokens: ct1 } = await runComprehension(epic, issue);

  // Stage 2: Refinement (consumes comprehension)
  const { result: refinement, cachedTokens: ct2 } = await runRefinement(epic, issue, comprehension);

  // Stage 3: Validation (consumes refined body)
  const { result: validation, cachedTokens: ct3 } = await runValidation(epic, issue, refinement.refinedBody);

  return {
    comprehension,
    refinedBody: refinement.refinedBody,
    validation,
    cachedTokens: {
      comprehension: ct1,
      refinement: ct2,
      validation: ct3
    }
  };
}
```

