import { runIssuePipeline } from '../pipeline/issue/runIssuePipeline';
import { gitlabClient } from '../services/gitlab/gitlabClient';
import { useIssueRefineryStore } from '../stores/issueRefineryStore';

/**
 * Refine the currently selected issue.
 * Updates store phase through: comprehending -> refining -> validating -> ready.
 */
export async function refineIssueAction(): Promise<void> {
  const { epic, selectedIssueIid, childIssues, setPhase, setComprehension, setRefinement, setValidation } = useIssueRefineryStore.getState();

  if (!epic || !selectedIssueIid) {
    throw new Error('No epic or issue selected');
  }

  const issue = childIssues.find(i => i.iid === selectedIssueIid);
  if (!issue) throw new Error('Issue not found in childIssues');

  try {
    setPhase('comprehending');
    const result = await runIssuePipeline(epic, issue);

    // Update store stage-by-stage for UI feedback
    setComprehension(result.comprehension, result.cachedTokens.comprehension);
    setPhase('refining');

    setRefinement(result.refinedBody, result.cachedTokens.refinement);
    setPhase('validating');

    setValidation(result.validation, result.cachedTokens.validation);
    setPhase('ready');
  } catch (error) {
    setPhase('error');
    useIssueRefineryStore.setState({ lastError: error as Error });
    throw error;
  }
}

/**
 * Publish refined draft to GitLab via PUT.
 * Transitions phase: ready -> publishing -> idle (success) or error (failure).
 */
export async function publishRefinedIssueAction(): Promise<void> {
  const { epic, selectedIssueIid, refinedDraft, setPhase } = useIssueRefineryStore.getState();

  if (!epic || !selectedIssueIid || !refinedDraft) {
    throw new Error('Cannot publish: missing epic, issue, or draft');
  }

  try {
    setPhase('publishing');
    await gitlabClient.updateIssue(epic.project_id, selectedIssueIid, { description: refinedDraft });
    setPhase('idle');
    // On next selectIssue, the published body will be the new original
  } catch (error) {
    setPhase('error');
    useIssueRefineryStore.setState({ lastError: error as Error });
    throw error;
  }
}
