import { useIssueRefineryStore } from '../../stores/issueRefineryStore';
import { gitlabClient } from '../../services/gitlab/gitlabClient';
import { useEffect, useState } from 'react';

interface ChildIssueListProps {
  // Passed from parent after LoadEpicModal
}

export function ChildIssueList() {
  const { epic, childIssues, selectedIssueIid, selectIssue, loadEpic } = useIssueRefineryStore();
  const [loading, setLoading] = useState(false);

  // Fetch all child issues with pagination
  useEffect(() => {
    if (!epic) return;

    async function fetchChildren() {
      setLoading(true);
      try {
        let allIssues: GitLabIssue[] = [];
        let page = 1;
        let hasMore = true;

        while (hasMore) {
          const response = await fetch(
            `${gitlabClient.baseURL}/groups/${epic.group_id}/issues?per_page=100&page=${page}&epic_id=${epic.id}`,
            { headers: { 'Authorization': `Bearer ${gitlabClient.token}` } }
          );
          const issues = await response.json();
          allIssues = allIssues.concat(issues);

          // Check Link header for next page
          const linkHeader = response.headers.get('Link');
          hasMore = linkHeader?.includes('rel="next"') || false;
          page++;
        }

        loadEpic(epic, allIssues);
      } finally {
        setLoading(false);
      }
    }

    fetchChildren();
  }, [epic?.id]);

  if (!epic) return <div>No epic loaded</div>;
  if (loading) return <div>Loading child issues...</div>;

  return (
    <div className="space-y-2">
      {childIssues.map(issue => (
        <button
          key={issue.iid}
          onClick={() => selectIssue(issue.iid)}
          className={selectedIssueIid === issue.iid ? 'bg-blue-100' : ''}
          aria-pressed={selectedIssueIid === issue.iid}
        >
          #{issue.iid} {issue.title}
        </button>
      ))}
    </div>
  );
}
