import { useIssueRefineryStore } from '../../stores/issueRefineryStore';
import { diffLines, Change } from 'diff';
import { useState } from 'react';
import ReactMarkdown from 'react-markdown';

export function RefinedIssueCard() {
  const { originalBody, refinedDraft, editDraft } = useIssueRefineryStore();
  const [view, setView] = useState<'side-by-side' | 'unified'>('side-by-side');
  const [editing, setEditing] = useState(false);
  const [editBuffer, setEditBuffer] = useState(refinedDraft);

  if (!refinedDraft) return null;

  const diff = diffLines(originalBody, refinedDraft);

  function handleSave() {
    editDraft(editBuffer);
    setEditing(false);
  }

  return (
    <div className="border rounded p-4">
      <div className="flex justify-between items-center mb-4">
        <h2>Refined Issue</h2>
        <div className="space-x-2">
          <button onClick={() => setView(view === 'side-by-side' ? 'unified' : 'side-by-side')}>
            Toggle View
          </button>
          <button onClick={() => setEditing(true)}>Edit</button>
        </div>
      </div>

      {editing ? (
        <div>
          <textarea
            value={editBuffer}
            onChange={e => setEditBuffer(e.target.value)}
            className="w-full h-96 font-mono"
          />
          <button onClick={handleSave}>Save</button>
          <button onClick={() => setEditing(false)}>Cancel</button>
        </div>
      ) : view === 'side-by-side' ? (
        <div className="grid grid-cols-2 gap-4">
          <div>
            <h3>Original</h3>
            <ReactMarkdown disallowedElements={['h1','h2','h3','h4','h5','h6']}>
              {originalBody}
            </ReactMarkdown>
          </div>
          <div>
            <h3>Refined</h3>
            <ReactMarkdown disallowedElements={['h1','h2','h3','h4','h5','h6']}>
              {refinedDraft}
            </ReactMarkdown>
          </div>
        </div>
      ) : (
        <div className="font-mono text-sm">
          {diff.map((part: Change, i: number) => (
            <div
              key={i}
              className={part.added ? 'bg-green-100' : part.removed ? 'bg-red-100' : ''}
            >
              {part.value}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
