import { useIssueRefineryStore } from '../../stores/issueRefineryStore';
import { publishRefinedIssueAction } from '../../actions/refineIssueAction';
import { useState } from 'react';

export function PublishButton() {
  const { phase, refinedDraft, userEditedDraft } = useIssueRefineryStore();
  const [showConfirm, setShowConfirm] = useState(false);

  const canPublish = phase === 'ready' && refinedDraft;

  async function handlePublish() {
    if (userEditedDraft) {
      setShowConfirm(true);
    } else {
      await publishRefinedIssueAction();
    }
  }

  async function confirmPublish() {
    setShowConfirm(false);
    await publishRefinedIssueAction();
  }

  return (
    <>
      <button
        onClick={handlePublish}
        disabled={!canPublish}
        aria-disabled={!canPublish}
      >
        {phase === 'publishing' ? 'Publishing...' : 'Publish to GitLab'}
      </button>

      {showConfirm && (
        <dialog open>
          <p>You've edited the draft. Publish your changes?</p>
          <button onClick={confirmPublish}>Yes, Publish</button>
          <button onClick={() => setShowConfirm(false)}>Cancel</button>
        </dialog>
      )}
    </>
  );
}
