              <h1>Issue #{selectedIssueIid}</h1>
              <button
                onClick={handleRefine}
                disabled={phase !== 'idle' && phase !== 'ready' && phase !== 'error'}
              >
                {phase === 'idle' || phase === 'ready' || phase === 'error' ? 'Refine' : 'Refining...'}
              </button>
            </div>

            {phase === 'idle' && (
              <div>
                <h2>Original Issue</h2>
                <ReactMarkdown>{originalBody}</ReactMarkdown>
              </div>
            )}

            <ComprehensionCard />
            <RefinedIssueCard />
            <ValidationCard />

            {phase === 'ready' && <PublishButton />}
          </>
        )}
      </main>

      <PromptCacheHUD />

      {showLoadModal && (
        <LoadEpicModal
          onClose={() => setShowLoadModal(false)}
          onEpicLoaded={(epic) => {
            // epic and children loaded via store in ChildIssueList
            setShowLoadModal(false);
          }}
        />
      )}
    </div>
  );
}
